class Solution:
    def diffWaysToCompute(self, expression: str) -> List[int]:
        memo = {}
        def dfs(s):
            if s in memo:
                return memo[s]
            if s.isdigit():
                return [int(s)]
            res = []
            for i, c in enumerate(s):
                if c in '+-*':
                    for a in dfs(s[:i]):
                        for b in dfs(s[i+1:]):
                            if c == '+': res.append(a + b)
                            elif c == '-': res.append(a - b)
                            else: res.append(a * b)
            memo[s] = res
            return res
        return dfs(expression)

